```javascript
const { Client, Intents } = require('discord.js');
const client = new Client({ 
  intents: [Intents.FLAGS.GUILDS, Intents.FLAGS.GUILD_MESSAGES]
});

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.on('interactionCreate', async interaction => {
  if (!interaction.isCommand()) return;

  const { commandName, options } = interaction;

  if (commandName === 'ban') {
    const user = options.getUser('user');
    const reason = options.getString('reason') || 'No reason provided';

    if (!interaction.member.permissions.has('BAN_MEMBERS')) {
      return interaction.reply({ content: "You don't have permission to ban members", ephemeral: true });
    }

    if (!user) {
      return interaction.reply({ content: "Please mention a user to ban", ephemeral: true });
    }

    const member = interaction.guild.members.resolve(user);
    if (!member) {
      return interaction.reply({ content: "User not found", ephemeral: true });
    }

    try {
      await member.ban({ reason: reason });
      interaction.reply({ content: `${member.user.tag} has been banned for ${reason}` });
    } catch (error) {
      interaction.reply({ content: "Error banning the user", ephemeral: true });
      console.error(error);
    }
  }
});

client.login('YOUR_TOKEN_HERE');
```

