```javascript
function checkForPrimeNumbers(arr) {
  for (let i = 0; i < arr.length; i++) {
    let num = arr[i];
    let isPrime = true;
    if (num <= 1) {
      isPrime = false;
    } else {
      for (let j = 2; j <= Math.sqrt(num); j++) {
        if (num % j === 0) {
          isPrime = false;
          break;
        }
      }
    }
    if (isPrime) {
      console.log(num + " is a prime number");
    }
  }
}

// Example usage:
let numbers = [2, 4, 5, 7, 9];
checkForPrimeNumbers(numbers);
```

In this example, the function `checkForPrimeNumbers` iterates through the array of numbers and checks each number to see if it's a prime number. If a prime number is found, it's printed to the console.

